            numblocks++;
        }

        if (!FindLargestSplittableBlock(
                lz77->size, done, *splitpoints, *npoints, &lstart, &lend))
        {
            break; /* No further split will probably reduce compression. */
        }

        if (lend - lstart < 10)
        {
            break;
        }
    }

    if (options->verbose)
    {
        PrintBlockSplitPoints(lz77, *splitpoints, *npoints);
    }

    free(done);
}

